1	import {
2	  PluginError,
3	  type AgentContext,
4	  type HookBus,
5	  type LlmCallInput,
6	  type LlmCallOutput,
7	  type Plugin,
8	} from '@ax/core';
9	import { buildPrompt } from './prompt.js';
10	import { validateGeneratedTitle } from './validate.js';
11	import type {
12	  GetInput,
13	  GetOutput,
14	  SetTitleInput,
15	  SetTitleOutput,
16	} from './types.js';
17	
18	// Storage key the admin "Model config" tab + the onboarding wizard write
19	// the runtime fast-model selection to. Lives at the kernel `storage:*`
20	// surface (NOT inside `credentials-store-db`'s `credential:v2:` namespace).
21	const FAST_MODEL_STORAGE_KEY = 'settings:fast-model';
22	
23	const PLUGIN_NAME = '@ax/conversation-titles';
24	const PLUGIN_VERSION = '0.0.0';
25	
26	const TITLE_MAX_TOKENS = 32;
27	// A touch of variety so titles don't all converge to the same dull phrase
28	// across similar conversations, but mostly deterministic ŌĆö a high-temperature
29	// title is a coin flip and we'd rather it be readable.
30	const TITLE_TEMPERATURE = 0.3;
31	
32	/**
33	 * Default `provider/model` reference ŌĆö preserves today's hardcoded haiku.
34	 * Operators override via the preset's `AX_TITLE_MODEL` env var, which flows
35	 * through `K8sPresetConfig.titles.model` to the factory's `cfg.model`.
36	 */
37	export const DEFAULT_TITLE_MODEL = 'anthropic/claude-haiku-4-5-20251001';
38	
39	export interface ConversationTitlesConfig {
40	  /**
41	   * Title-LLM model reference in the form `<provider>/<model-id>`.
42	   * Splits on the first `/`. Provider becomes the bus hook name suffix
43	   * (`llm:call:<provider>`); model-id flows into the call's `model` field.
44	   *
45	   * Default: `'anthropic/claude-haiku-4-5-20251001'`.
46	   */
47	  model?: string;
48	}
49	
50	export interface ParsedModelRef {
51	  provider: string;
52	  modelId: string;
53	}
54	
55	/**
56	 * Parse a `provider/model-id` reference. Splits on the FIRST `/` so a
57	 * future routing-style value like `openrouter/anthropic/claude-3-5-sonnet`
58	 * yields provider=`openrouter`, modelId=`anthropic/claude-3-5-sonnet`.
59	 *
60	 * Throws `PluginError({ code: 'invalid-config' })` on:
61	 *   - empty string
62	 *   - missing `/`
63	 *   - leading `/` (empty provider)
64	 *   - trailing `/` (empty model-id)
65	 */
66	export function parseModelRef(ref: string): ParsedModelRef {
67	  if (typeof ref !== 'string' || ref.length === 0) {
68	    throw new PluginError({
69	      code: 'invalid-config',
70	      plugin: PLUGIN_NAME,
71	      message: `model must be 'provider/model-id' (got empty value)`,
72	    });
73	  }
74	  const idx = ref.indexOf('/');
75	  if (idx <= 0 || idx === ref.length - 1) {
76	    throw new PluginError({
77	      code: 'invalid-config',
78	      plugin: PLUGIN_NAME,
79	      message: `model must be 'provider/model-id' (got: ${ref})`,
80	    });
81	  }
82	  return { provider: ref.slice(0, idx), modelId: ref.slice(idx + 1) };
83	}
84	
85	/**
86	 * `chat:turn-end` payload shape. The bus delivers whatever the publisher
87	 * fired; we only care about `role`. Other fields (contentBlocks, reqId,
88	 * reason) may be present but are unused here ŌĆö we re-read the canonical
89	 * transcript via `conversations:get`.
90	 */
91	interface TurnEndPayload {
92	  role?: 'user' | 'assistant' | 'tool';
93	  contentBlocks?: unknown[];
94	  reqId?: string;
95	  reason?: string;
96	}
97	
98	/**
99	 * Build the `@ax/conversation-titles` plugin. Subscribes to `chat:turn-end`,
100	 * fires the title-LLM call after the first assistant turn lands on a
101	 * still-untitled conversation, and persists the validated result via
102	 * `conversations:set-title`.
103	 *
104	 * Idempotency / re-delivery safety: we use `ifNull: true` on the set-title
105	 * call so a slow LLM round-trip can never clobber a user-driven rename.
106	 * At-least-once subscriber delivery is therefore safe.
107	 */
108	export function createConversationTitlesPlugin(
109	  cfg: ConversationTitlesConfig = {},
110	): Plugin {
111	  const fallbackRef = cfg.model ?? DEFAULT_TITLE_MODEL;
112	  // Eagerly validate the fallback config so a typo fails at boot, not at
113	  // first chat:turn-end. The runtime override path goes through
114	  // parseModelRef again so a bad storage value is caught before it lands
115	  // in an llm:call.
116	  const fallbackParsed = parseModelRef(fallbackRef);
117	  const fallbackHook = `llm:call:${fallbackParsed.provider}`;
118	
119	  return {
120	    manifest: {
121	      name: PLUGIN_NAME,
122	      version: PLUGIN_VERSION,
123	      registers: [],
124	      // `storage:get` is a soft dep ŌĆö declared so the topo-sort orders us
125	      // after any storage plugin that registers it, but the runtime path
126	      // tolerates `storage:get` being absent (presets that strip it just
127	      // fall through to cfg.model). The configured fallback llm hook is
128	      // declared as the hard provider; a runtime override that points to a
129	      // different provider hook is resolved against the bus dynamically.
130	      calls: [fallbackHook, 'storage:get', 'conversations:get', 'conversations:set-title'],
131	      subscribes: ['chat:turn-end'],
132	    },
133	    async init({ bus }) {
134	      bus.subscribe<TurnEndPayload>(
135	        'chat:turn-end',
136	        PLUGIN_NAME,
137	        async (ctx, payload) => {
138	          // Subscriber posture: NEVER throw. The bus already swallows + logs
139	          // subscriber errors, but doing it here too keeps the warning under
140	          // a stable log key and pins the plugin name in the entry rather
141	          // than letting the bus's generic `hook_subscriber_failed` swallow
142	          // the context.
143	          try {
144	            const resolved = await resolveTitleModel(bus, ctx, {
145	              fallbackRef,
146	              fallbackHook,
147	              fallbackModelId: fallbackParsed.modelId,
148	            });
149	            await handleTurnEnd(bus, ctx, payload, {
150	              llmCallHook: resolved.llmCallHook,
151	              modelId: resolved.modelId,
152	            });
153	          } catch (err) {
154	            ctx.logger.warn('conversation_titles_subscriber_failed', {
155	              err: err instanceof Error ? err : new Error(String(err)),
156	              ...(ctx.conversationId !== undefined
157	                ? { conversationId: ctx.conversationId }
158	                : {}),
159	            });
160	          }
161	          return undefined;
162	        },
163	      );
164	    },
165	  };
166	}
167	
168	interface ResolvedTitleModel {
169	  llmCallHook: string;
170	  modelId: string;
171	}
172	
173	/**
174	 * Resolve the title-LLM model for this turn. Reads the runtime override
175	 * from `storage:get('settings:fast-model')` if available; otherwise uses
176	 * the plugin's configured fallback.
177	 *
178	 * The override exists so the operator can change the title model from the
179	 * admin UI without redeploying. The wizard's first-run write seeds the
180	 * same key, so post-onboarding chat uses the operator's chosen model
181	 * straight away.
182	 *
183	 * Failure modes (silently fall back to cfg.model):
184	 *  - `storage:get` not registered ŌåÆ no storage layer in this preset.
185	 *  - `storage:get` throws ŌåÆ transient backend issue; titling is a nice-to-
186	 *    have, not load-bearing.
187	 *  - Decoded value is empty or not a valid `provider/model-id` ref.
188	 */
189	async function resolveTitleModel(
190	  bus: HookBus,
191	  ctx: AgentContext,
192	  fallback: {
193	    fallbackRef: string;
194	    fallbackHook: string;
195	    fallbackModelId: string;
196	  },
197	): Promise<ResolvedTitleModel> {
198	  const fallbackResult: ResolvedTitleModel = {
199	    llmCallHook: fallback.fallbackHook,
200	    modelId: fallback.fallbackModelId,
201	  };
202	  if (!bus.hasService('storage:get')) return fallbackResult;
203	  let value: Uint8Array | undefined;
204	  try {
205	    const r = await bus.call<
206	      { key: string },
207	      { value: Uint8Array | undefined }
208	    >('storage:get', ctx, { key: FAST_MODEL_STORAGE_KEY });
209	    value = r.value;
210	  } catch (err) {
211	    ctx.logger.debug('conversation_titles_storage_get_failed', {
212	      err: err instanceof Error ? err.message : String(err),
213	    });
214	    return fallbackResult;
215	  }
216	  if (value === undefined || value.length === 0) return fallbackResult;
217	  let text: string;
218	  try {
219	    text = new TextDecoder('utf-8', { fatal: true }).decode(value);
220	  } catch {
221	    return fallbackResult;
222	  }
223	  if (text.length === 0) return fallbackResult;
224	  let parsed: ParsedModelRef;
225	  try {
226	    parsed = parseModelRef(text);
227	  } catch {
228	    ctx.logger.warn('conversation_titles_invalid_storage_ref', {
229	      // Length only ŌĆö the raw value may contain a provider name we don't
230	      // want in logs verbatim.
231	      length: text.length,
232	      fallback: fallback.fallbackRef,
233	    });
234	    return fallbackResult;
235	  }
236	  const overrideHook = `llm:call:${parsed.provider}`;
237	  // The override pointed at a provider whose llm:call:<provider> hook
238	  // isn't registered in this deployment. Fall back to cfg.model so
239	  // titling still runs ŌĆö the configured fallback hook is guaranteed
240	  // to be present (it's declared as a hard call in the manifest).
241	  if (!bus.hasService(overrideHook)) {
242	    ctx.logger.warn('conversation_titles_override_hook_missing', {
243	      provider: parsed.provider,
244	      fallback: fallback.fallbackRef,
245	    });
246	    return fallbackResult;
247	  }
248	  return {
249	    llmCallHook: overrideHook,
250	    modelId: parsed.modelId,
251	  };
252	}
253	
254	async function handleTurnEnd(
255	  bus: HookBus,
256	  ctx: AgentContext,
257	  payload: TurnEndPayload,
258	  cfg: { llmCallHook: string; modelId: string },
259	): Promise<void> {
260	  // Title fires only on the assistant's reply. User and tool turns are
261	  // signal-poor for a one-line summary, and waiting for the assistant
262	  // means the transcript already has the user prompt to summarize.
263	  if (payload.role !== 'assistant') return;
264	  if (ctx.conversationId === undefined) return;
265	
266	  // Read the canonical transcript + check for an existing title. A
267	  // separate read here (rather than relying on the payload) gives us
268	  // the user's prompt + every prior turn, which the title model needs
269	  // for context.
270	  const conv = await bus.call<GetInput, GetOutput>(
271	    'conversations:get',
272	    ctx,
273	    {
274	      conversationId: ctx.conversationId,
275	      userId: ctx.userId,
276	    },
277	  );
278	  if (conv.conversation.title !== null) return;
279	  if (conv.turns.length === 0) return;
280	
281	  // Only auto-title on the first assistant turn. If that attempt was lost
282	  // (LLM error, validation rejected the output), we deliberately don't
283	  // retry on later turns ŌĆö the design says "after the first assistant
284	  // turn", and re-firing per turn would mean later titles summarize a
285	  // different transcript than the design specifies (and would expand
286	  // LLM spend silently). Manual retitling is a future feature.
287	  const assistantTurnCount = conv.turns.filter(
288	    (t) => t.role === 'assistant',
289	  ).length;
290	  if (assistantTurnCount !== 1) return;
291	
292	  const prompt = buildPrompt(conv.turns);
293	  const llmOut = await bus.call<LlmCallInput, LlmCallOutput>(
294	    cfg.llmCallHook,
295	    ctx,
296	    {
297	      model: cfg.modelId,
298	      maxTokens: TITLE_MAX_TOKENS,
299	      system: prompt.system,
300	      messages: [{ role: 'user', content: prompt.user }],
301	      temperature: TITLE_TEMPERATURE,
302	    },
303	  );
304	
305	  const title = validateGeneratedTitle(llmOut.text);
306	  if (title === null) {
307	    // The model gave us a useless title (empty / "Untitled" / pure
308	    // whitespace). Leave the row's title NULL ŌĆö better than writing
309	    // garbage. Logged at debug because this is expected to happen
310	    // occasionally on signal-poor first turns and isn't actionable.
311	    // SECURITY: `llmOut.text` is untrusted model-generated content
312	    // (CLAUDE.md invariant 5). Logging it would violate this plugin's
313	    // SECURITY.md ("we don't log prompt-derived text") and could
314	    // surface user content in operator-visible logs. The length is a
315	    // useful signal (very long = model misbehaving) without leaking
316	    // content.
317	    ctx.logger.debug('conversation_titles_validation_skipped', {
318	      conversationId: ctx.conversationId,
319	      rawLength: llmOut.text.length,
320	    });
321	    return;
322	  }
323	
324	  const result = await bus.call<SetTitleInput, SetTitleOutput>(
325	    'conversations:set-title',
326	    ctx,
327	    {
328	      conversationId: ctx.conversationId,
329	      userId: ctx.userId,
330	      title,
331	      ifNull: true,
332	    },
333	  );
334	  if (!result.updated) {
335	    // Race: a concurrent caller (probably a user-driven rename, possibly
336	    // a duplicate subscriber delivery) titled the row first. Our `ifNull`
337	    // guard caught it; nothing to do.
338	    ctx.logger.debug('conversation_titles_already_set', {
339	      conversationId: ctx.conversationId,
340	    });
341	  }
342	}
