1	/**
2	 * AX-backed ThreadHistoryAdapter (Task 20).
3	 *
4	 * Hydrates conversation turns from
5	 * `GET /api/chat/conversations/:id[?includeThinking=true]` (Task 11). The
6	 * `?includeThinking` query param lets the per-message UI toggle (Task 21)
7	 * pull thinking blocks on demand without a wholesale re-design.
8	 *
9	 * Wire shape source: `src/wire/chat.ts` `GetConversationResponse` ŌĆö
10	 *   { conversation: {...}, turns: [{ role, contentBlocks, ... }] }
11	 *
12	 * The adapter maps each turn's `contentBlocks` (Anthropic-compatible
13	 * @ax/ipc-protocol shape) to assistant-ui's UIMessage `parts` array. Only
14	 * `text` blocks have a 1:1 mapping in MVP; `image` / `file` blocks
15	 * surface as plain text with the upstream id (Tasks 17-21 are scoped to
16	 * text + thinking; richer rendering lands in a follow-up).
17	 *
18	 * `withFormat` is the path `useExternalHistory` calls. The bare `load()`
19	 * exists only because the interface requires it.
20	 */
21	import type { ThreadHistoryAdapter } from '@assistant-ui/react';
22	import type { ContentBlock } from '@ax/ipc-protocol';
23	
24	interface Turn {
25	  turnId: string;
26	  turnIndex: number;
27	  role: 'user' | 'assistant' | 'tool';
28	  contentBlocks: ContentBlock[];
29	  createdAt: string;
30	}
31	
32	interface GetConversationResponse {
33	  conversation: { conversationId: string; title: string | null };
34	  turns: Turn[];
35	}
36	
37	/**
38	 * Tool result lookup keyed by `tool_use_id`. Built once across all turns so
39	 * an assistant turn's `tool_use` block can be paired with the tool turn that
40	 * carries the corresponding `tool_result`.
41	 */
42	type ToolResultMap = Map<
43	  string,
44	  { content: string; isError: boolean }
45	>;
46	
47	const flattenToolResultContent = (
48	  content: unknown,
49	): string => {
50	  if (typeof content === 'string') return content;
51	  if (Array.isArray(content)) {
52	    return content
53	      .filter((c): c is { type: 'text'; text: string } =>
54	        !!c && typeof c === 'object' && (c as { type?: string }).type === 'text',
55	      )
56	      .map((c) => c.text)
57	      .join('\n');
58	  }
59	  return '';
60	};
61	
62	/** Convert AX content blocks to assistant-ui message parts. */
63	function blocksToParts(
64	  blocks: ContentBlock[],
65	  toolResults: ToolResultMap,
66	): Array<Record<string, unknown>> {
67	  const parts: Array<Record<string, unknown>> = [];
68	  for (const block of blocks) {
69	    if (block.type === 'text') {
70	      parts.push({ type: 'text', text: block.text });
71	      continue;
72	    }
73	    if (block.type === 'thinking') {
74	      // Thinking blocks come through only when ?includeThinking=true.
75	      // Tag with providerMetadata so the renderer can hide / collapse.
76	      parts.push({
77	        type: 'text',
78	        text: block.thinking ?? '',
79	        providerMetadata: { ax: { thinking: true } },
80	      });
81	      continue;
82	    }
83	    if (block.type === 'redacted_thinking') {
84	      // No human-readable content ŌĆö surface as a placeholder when present.
85	      parts.push({
86	        type: 'text',
87	        text: '[redacted thinking]',
88	        providerMetadata: { ax: { thinking: true, redacted: true } },
89	      });
90	      continue;
91	    }
92	    if (block.type === 'image') {
93	      // Anthropic image source: data URL or external reference.
94	      const src = block.source;
95	      if (src?.type === 'base64') {
96	        parts.push({
97	          type: 'image',
98	          image: `data:${src.media_type};base64,${src.data}`,
99	        });
100	      } else if (src?.type === 'url') {
101	        parts.push({ type: 'image', image: src.url });
102	      } else {
103	        parts.push({ type: 'text', text: '[malformed image]' });
104	      }
105	      continue;
106	    }
107	    if (block.type === 'attachment') {
108	      // Phase 3 (2026-05-18): translate stored `attachment` content blocks to
109	      // assistant-ui's `file` part shape. The `data` URL carries the
110	      // workspace-relative path (base64url-encoded) so AttachmentChip can
111	      // decode it and feed `GET /api/files`.
112	      const encodedPath = base64url(block.path);
113	      parts.push({
114	        type: 'file',
115	        data: `ax://attachment-path/${encodedPath}`,
116	        mediaType: block.mediaType,
117	        filename: block.displayName,
118	      });
119	      continue;
120	    }
121	    if (block.type === 'tool_use') {
122	      // Emit an AI SDK v5 dynamic-tool UIMessage part. assistant-ui's
123	      // react-ai-sdk bridge converts these into tool-call ThreadMessage
124	      // parts, which Thread.tsx renders via ToolGroup + ToolFallback.
125	      const matched = toolResults.get(block.id);
126	      const part: Record<string, unknown> = {
127	        type: 'dynamic-tool',
128	        toolName: block.name,
129	        toolCallId: block.id,
130	        input: block.input,
131	      };
132	      if (matched) {
133	        part.state = 'output-available';
134	        part.output = matched.content;
135	        if (matched.isError) {
136	          // The bridge prefers `output-error` when an explicit errorText is
137	          // present. Match that shape so the failed group renders red.
138	          part.state = 'output-error';
139	          part.errorText = matched.content || 'tool failed';
140	          delete part.output;
141	        }
142	      } else {
143	        // Result not in this transcript (turn streaming dropped it, or the
144	        // tool is still in flight). Mark as input-available so the row
145	        // shows up; the absence of output is rendered as a quiet "running".
146	        part.state = 'input-available';
147	      }
148	      parts.push(part);
149	      continue;
150	    }
151	    if (block.type === 'tool_result') {
152	      // Tool results live in tool-role turns; collectToolResults() pulls
153	      // them into the lookup map so the matching assistant turn's tool_use
154	      // can reference them. An orphan here means there's no preceding
155	      // tool_use ŌĆö drop silently.
156	      continue;
157	    }
158	    // Anything else falls through as a text placeholder so the message
159	    // renders rather than disappearing silently.
160	    parts.push({
161	      type: 'text',
162	      text: `[block: ${(block as { type: string }).type}]`,
163	    });
164	  }
165	  if (parts.length === 0) {
166	    parts.push({ type: 'text', text: '' });
167	  }
168	  return parts;
169	}
170	
171	/**
172	 * Public-facing wrapper used by render-side code and tests. The optional
173	 * second arg carries opts that downstream renderers may want (e.g.
174	 * conversationId for the chip's GET /api/files URL); this function itself
175	 * doesn't read them ŌĆö the `useConversationId` hook (Task 14) provides
176	 * them to chips at render time.
177	 *
178	 * Internally delegates to `blocksToParts` with an empty tool-result map
179	 * since attachment translation never needs the cross-turn tool_use Ōåö
180	 * tool_result join.
181	 */
182	export function contentBlocksToAuiParts(
183	  blocks: ContentBlock[],
184	  _opts?: { conversationId?: string },
185	): Array<Record<string, unknown>> {
186	  return blocksToParts(blocks, new Map());
187	}
188	
189	/**
190	 * Encode a workspace-relative path as base64url so it can ride safely as
191	 * the path segment of `ax://attachment-path/<...>` URLs (no raw slashes
192	 * or `+`/`=` chars).
193	 *
194	 * Goes through TextEncoder/TextDecoder rather than `btoa(input)` directly
195	 * because `btoa` throws on code points > 0xFF ŌĆö Unicode filenames (CJK,
196	 * emoji) would otherwise blow up here.
197	 */
198	function base64url(input: string): string {
199	  const bytes = new TextEncoder().encode(input);
200	  let binary = '';
201	  for (let i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i]!);
202	  return btoa(binary)
203	    .replace(/\+/g, '-')
204	    .replace(/\//g, '_')
205	    .replace(/=+$/, '');
206	}
207	
208	/**
209	 * Decode an `ax://attachment-path/<base64url>` URL back to the original
210	 * workspace-relative path. Used by `AttachmentChip` (Task 11) to build
211	 * its `GET /api/files` request. Returns `null` for non-ax URLs or any
212	 * decode failure.
213	 *
214	 * Symmetrically to `base64url`, decodes through TextDecoder so multi-byte
215	 * UTF-8 sequences (Unicode filenames) round-trip correctly.
216	 */
217	export function decodeAttachmentPath(url: string): string | null {
218	  const PREFIX = 'ax://attachment-path/';
219	  if (!url.startsWith(PREFIX)) return null;
220	  const encoded = url.slice(PREFIX.length);
221	  const padded = encoded
222	    .replace(/-/g, '+')
223	    .replace(/_/g, '/');
224	  try {
225	    const binary = atob(padded + '==='.slice(0, (4 - (padded.length % 4)) % 4));
226	    const bytes = new Uint8Array(binary.length);
227	    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
228	    return new TextDecoder().decode(bytes);
229	  } catch {
230	    return null;
231	  }
232	}
233	
234	/** Build a tool_use_id ŌåÆ result lookup from every block we'll see. */
235	function collectToolResults(turns: Turn[]): ToolResultMap {
236	  const map: ToolResultMap = new Map();
237	  for (const turn of turns) {
238	    for (const block of turn.contentBlocks) {
239	      if (block.type === 'tool_result') {
240	        map.set(block.tool_use_id, {
241	          content: flattenToolResultContent(block.content),
242	          isError: block.is_error === true,
243	        });
244	      }
245	    }
246	  }
247	  return map;
248	}
249	
250	/**
251	 * Build an AX-backed history adapter.
252	 *
253	 * @param getConversationId ŌĆö resolves to the conversationId for the
254	 *   currently-active thread. Returns `undefined` when no conversation
255	 *   has been minted yet (fresh thread); the adapter returns an empty
256	 *   list in that case so the runtime starts on the welcome screen.
257	 * @param options.includeThinking ŌĆö when true, the adapter fetches with
258	 *   `?includeThinking=true`. Default false (J4). Tasks 21's per-message
259	 *   toggle re-creates the adapter with this flipped to refetch.
260	 */
261	export const createAxHistoryAdapter = (
262	  getConversationId: () => string | undefined,
263	  options: { includeThinking?: boolean } = {},
264	): ThreadHistoryAdapter => {
265	  const includeThinking = options.includeThinking === true;
266	  return {
267	    async load() {
268	      // Direct load (ThreadMessage format) ŌĆö required by the interface
269	      // but useExternalHistory calls `withFormat` instead.
270	      return { messages: [] };
271	    },
272	
273	    async append() {
