1	// ---------------------------------------------------------------------------
2	// Phase 2 ŌĆö attachment-translation pass.
3	//
4	// Maps `ContentBlock[]` (the canonical stored-transcript shape) onto the
5	// Anthropic SDK's user-message content shape, one block at a time. Runs
6	// at user-message handoff to the SDK (and again on transcript replay).
7	//
8	// Translation rules per the design doc + weak-model accommodation:
9	//   - `text` / `tool_use` / `tool_result` / etc.: pass through unchanged.
10	//   - `attachment` with mediaType image/*: read bytes via injected reader,
11	//     emit Anthropic `image` block with base64 source.
12	//   - `attachment` with mediaType application/pdf AND
13	//     `supportsDocumentBlocks`: read bytes, emit `document` block.
14	//   - `attachment` with a text-ish mediaType (text/*, application/json,
15	//     application/xml, application/yaml) AND sizeBytes Ōēż MAX_INLINE_BYTES:
16	//     read bytes, inline as a text block with a provenance preamble so
17	//     the model gets the content directly. Critical for weaker models
18	//     that can't reliably figure out "the file is at <path>, I should
19	//     call Read" ŌĆö the bytes are just there in the prompt.
20	//   - Anything else (including missing bytes for image/pdf, oversized
21	//     text, unrecognized binary types): text mention
22	//     `"User attached '<displayName>' at <path> (<mediaType>)"`.
23	//
24	// The stored-transcript shape is NEVER modified ŌĆö translation transforms
25	// blocks only on the way to the SDK. Web-UI download paths (Phase 3) read
26	// from the stored transcript and resolve the `attachment.path` via
27	// `attachments:download`, unaffected by what the runner did mid-turn.
28	//
29	// Byte fetch is via injected `readWorkspace` ŌĆö the runner wires this to
30	// `client.call('workspace.read', { path })` at startup, but the
31	// translation function itself stays pure-function-testable.
32	// ---------------------------------------------------------------------------
33	
34	import type { AttachmentBlock, ContentBlock } from '@ax/ipc-protocol';
35	
36	// 64 KiB. Text content under this size is inlined into the SDK prompt
37	// directly so weaker models don't need to know about the Read tool. At
38	// ~25K tokens worst case for dense ASCII this stays a tiny fraction of
39	// any production Claude context. Files above this fall back to a text
40	// mention; a future "fetch_attachment" tool can serve the long tail.
41	export const MAX_INLINE_BYTES = 64 * 1024;
42	
43	// MIME types whose bytes are safely renderable as UTF-8 text in a prompt.
44	// We keep the list small and explicit rather than pattern-matching every
45	// `application/*+json` variant ŌĆö adding a type is a one-line change.
46	function isInlineableTextMediaType(mediaType: string): boolean {
47	  if (mediaType.startsWith('text/')) return true;
48	  return (
49	    mediaType === 'application/json' ||
50	    mediaType === 'application/xml' ||
51	    mediaType === 'application/yaml' ||
52	    mediaType === 'application/x-yaml'
53	  );
54	}
55	
56	export interface WorkspaceReader {
57	  (path: string): Promise<
58	    { found: true; bytesBase64: string } | { found: false }
59	  >;
60	}
61	
62	export interface TranslationOptions {
63	  readWorkspace: WorkspaceReader;
64	  supportsDocumentBlocks: boolean;
65	}
66	
67	// Anthropic SDK shape ŌĆö the union we emit. Loose typing here keeps the
68	// runner decoupled from the pinned SDK's internal types; the SDK
69	// accepts any compatible shape on the `message.content` field.
70	type AnthropicUserContentBlock =
71	  | { type: 'text'; text: string }
72	  | {
73	      type: 'image';
74	      source: { type: 'base64'; media_type: string; data: string };
75	    }
76	  | {
77	      type: 'document';
78	      source: { type: 'base64'; media_type: string; data: string };
79	    }
80	  // Pass-through for blocks we don't touch (tool_use, thinking, etc.).
81	  // The SDK validates these by its own schema downstream.
82	  | Record<string, unknown>;
83	
84	function textMention(att: AttachmentBlock): { type: 'text'; text: string } {
85	  return {
86	    type: 'text',
87	    text: `User attached '${att.displayName}' at ${att.path} (${att.mediaType})`,
88	  };
89	}
90	
91	async function translateAttachment(
92	  att: AttachmentBlock,
93	  opts: TranslationOptions,
94	): Promise<AnthropicUserContentBlock> {
95	  const isImage = att.mediaType.startsWith('image/');
96	  const isPdf = att.mediaType === 'application/pdf';
97	  const isInlineableText =
98	    isInlineableTextMediaType(att.mediaType) &&
99	    att.sizeBytes <= MAX_INLINE_BYTES;
100	
101	  // Anything not in the "fetch and inline" set short-circuits to text
102	  // mention without paying the IPC cost.
103	  if (!isImage && !(isPdf && opts.supportsDocumentBlocks) && !isInlineableText) {
104	    return textMention(att);
105	  }
106	  // IPC failures (host down, retries exhausted, schema-drift rejection)
107	  // degrade to a text mention so the model still sees the attachment's
108	  // provenance even when bytes are unavailable. Throwing here would abort
109	  // the entire user-message handoff to the SDK and terminate the turn ŌĆö
110	  // disproportionate for a single missing image.
111	  let read: { found: true; bytesBase64: string } | { found: false };
112	  try {
113	    read = await opts.readWorkspace(att.path);
114	  } catch {
115	    return textMention(att);
116	  }
117	  if (!read.found) {
118	    return textMention(att);
119	  }
120	  if (isImage) {
121	    return {
122	      type: 'image',
123	      source: {
124	        type: 'base64',
125	        media_type: att.mediaType,
126	        data: read.bytesBase64,
127	      },
128	    };
129	  }
130	  if (isPdf && opts.supportsDocumentBlocks) {
131	    return {
132	      type: 'document',
133	      source: {
134	        type: 'base64',
135	        media_type: 'application/pdf',
136	        data: read.bytesBase64,
137	      },
138	    };
139	  }
140	  // Inlineable text branch. Decode permissively ŌĆö invalid UTF-8 sequences
141	  // become U+FFFD rather than throwing, so a mis-labeled binary file
142	  // produces noisy output rather than a turn-fatal error. The model can
143	  // see the noise and infer what happened; we don't pretend it's clean
144	  // content. (mediaType is server-claimed; we trust the claim and let
145	  // the model handle any mismatch ŌĆö same posture the design doc takes
146	  // on MIME-spoofing.)
147	  const content = Buffer.from(read.bytesBase64, 'base64').toString('utf8');
148	  return {
149	    type: 'text',
150	    text: `User attached '${att.displayName}' (${att.mediaType}, ${att.sizeBytes} bytes):\n\n${content}`,
151	  };
152	}
153	
154	export async function translateContentBlocks(
155	  blocks: readonly ContentBlock[],
156	  opts: TranslationOptions,
157	): Promise<AnthropicUserContentBlock[]> {
158	  const out: AnthropicUserContentBlock[] = [];
159	  for (const block of blocks) {
160	    if (block.type === 'attachment') {
161	      out.push(await translateAttachment(block, opts));
162	      continue;
163	    }
164	    // `attachment_ref` is a transit-only variant ŌĆö it should never reach
165	    // the runner. If it does, it's a host bug; emit a defensive text
166	    // mention so we don't crash mid-turn, and log via a thrown Error
167	    // would be safer but turn-fatal. Trade-off: silent skip is wrong
168	    // (model gets nothing), text mention preserves provenance.
169	    if (block.type === 'attachment_ref') {
170	      out.push({
171	        type: 'text',
172	        text: `[runner: attachment_ref ${(block as { attachmentId: string }).attachmentId} not committed]`,
173	      });
174	      continue;
175	    }
176	    out.push(block as AnthropicUserContentBlock);
177	  }
178	  return out;
179	}
