}

async function getConversation(
  store: ConversationStore,
  bus: HookBus,
  ctx: AgentContext,
  input: GetInput,
): Promise<GetOutput> {
  const conv = await store.getByIdNotDeleted(input.conversationId);
  if (conv === null || conv.userId !== input.userId) {
    throw new PluginError({
      code: 'not-found',
      plugin: PLUGIN_NAME,
      hookName: 'conversations:get',
      message: `conversation '${input.conversationId}' not found`,
    });
  }
  await assertAgentReachable(
    bus,
    ctx,
    conv.agentId,
    input.userId,
    'conversations:get',
  );
  // Phase D (2026-05-02): the transcript lives in the runner's native
  // jsonl file inside the workspace, NOT in conversation_turns. We
  // skip the workspace round-trip entirely when runnerSessionId is
  // null (pre-Phase-C rows or fresh rows whose first turn hasn't
  // landed yet ŌĆö see Q3=(a)). The wire shape on
  // `conversations:get` is unchanged.
  //
  // Build a synthetic ctx scoped to the conversation's owner before the
  // workspace round-trip. The host-side workspace plugins (workspace-git,
  // workspace-git-server-client) derive their workspaceId from
  // (ctx.userId, ctx.agentId); the runner pod's commit-notify wrote the
  // jsonl into ws-<hash([conv.userId, conv.agentId])>. Channel-web calls
  // us with `initCtx` (userId='system', agentId='@ax/channel-web') ŌĆö
  // forwarding that ctx into workspace:list looks up a different (empty)
  // workspaceId and returns no matches. The auth gate (input.userId ===
  // conv.userId, plus assertAgentReachable above) already proved the
  // caller owns this conversation, so it's safe to lift conv.userId /
  // conv.agentId into the synthetic ctx for the read.
  const turns =
    conv.runnerSessionId === null
      ? []
      : await readTranscriptFromWorkspace(
          bus,
          makeAgentContext({
            reqId: ctx.reqId,
            sessionId: ctx.sessionId,
            userId: conv.userId,
            agentId: conv.agentId,
            logger: ctx.logger,
            workspace: ctx.workspace,
          }),
          conv.runnerSessionId,
        );
  return { conversation: conv, turns };
}

/**
 * Phase D. Locate the runner's jsonl transcript by sessionId and parse it
 * into the canonical Turn[] shape. We glob via `workspace:list` instead of
 * hardcoding the SDK's cwd-encoding rule (which depends on
 * `AX_WORKSPACE_ROOT` and isn't a stable contract).
 *
 * Two graceful-empty paths preserve subscriber expectations:
 *   - `workspace:list` returns no matches ŌåÆ file hasn't been written
 *     yet OR a pre-Phase-C row that bound a runner session before the
 *     workspace plugin started persisting them.
 *   - `workspace:read` returns `{found:false}` ŌåÆ race between list and
 *     read (the file existed when listed, then vanished).
 */
async function readTranscriptFromWorkspace(
  bus: HookBus,
  ctx: AgentContext,
  runnerSessionId: string,
): Promise<Turn[]> {
  const list = await bus.call<WorkspaceListInput, WorkspaceListOutput>(
    'workspace:list',
    ctx,
    { pathGlob: `.claude/projects/**/${runnerSessionId}.jsonl` },
  );
  if (list.paths.length === 0) return [];
  // Multiple matches are not expected ŌĆö sessionIds are UUIDs and the
  // workspace stores at most one jsonl per session ŌĆö but if it
  // happens, the list is sorted ascending by the workspace plugin so
  // picking the first entry is deterministic.
  const path = list.paths[0]!;
  const read = await bus.call<WorkspaceReadInput, WorkspaceReadOutput>(
    'workspace:read',
    ctx,
    { path },
  );
  if (!read.found) return [];
  return parseJsonlToTurns(read.bytes);
}

async function listConversations(
  store: ConversationStore,
  bus: HookBus,
  ctx: AgentContext,
  input: ListInput,
): Promise<ListOutput> {
  // J1: when agentId is supplied, gate via agents:resolve. When absent,
  // ACL is implicit (filter by user_id only) ŌĆö the user's own
  // conversations are always reachable to them.
  if (input.agentId !== undefined) {
    await assertAgentReachable(
      bus,

/**
 * Phase 1 (attachments & artifacts, 2026-05-15). Transient reference to a
 * pending upload staged in `@ax/attachments`'s temp store.
 *
 * Lives only on the POST /api/chat/messages request body. The chat-messages
 * handler resolves `attachmentId` ŌåÆ workspace path via `attachments:commit`
 * and rewrites this block as an `attachment` block BEFORE the message reaches
 * conversation storage or any subscriber. Never appears in stored transcripts.
 *
 * Boundary review (I1): `attachmentId` is workspace-vocab ŌĆö opaque server-
 * minted identifier, no backend leak (no `lfs_oid`, no `bucket`).
 */
export const AttachmentRefBlockSchema = z.object({
  type: z.literal('attachment_ref'),
  attachmentId: z.string().min(1),
});
export type AttachmentRefBlock = z.infer<typeof AttachmentRefBlockSchema>;

/**
 * Phase 1 (attachments & artifacts, 2026-05-15). User-attached file OR
 * agent-published artifact as it appears in a stored conversation turn.
 *
 * The runner translates this variant to Anthropic-compatible types before
 * the LLM call (image/* ŌåÆ `image` block; PDF ŌåÆ `document` if SDK supports;
 * else text mention). This block is the canonical stored form (I4 ŌĆö single
 * source of truth); the Anthropic shape is derived per LLM call.
 *
 * `path` is workspace-relative (e.g. ".ax/uploads/<conv>/<turn>/file.pdf"),
 * not sandbox-absolute. Resolution: workspace:read(path) at current HEAD.
 */
/**
 * `path` is workspace-relative ŌĆö defense-in-depth refusal of absolute
 * paths, `..` traversal segments, Windows drive roots, and NUL bytes at
 * the wire boundary so a malformed value can't reach storage or
 * `attachments:download` and bypass the path-scope ACL.
 */
export function isWorkspaceRelativePath(value: string): boolean {
  if (value.startsWith('/') || value.startsWith('\\')) return false;
  if (value.includes('\0')) return false;
  if (/^[A-Za-z]:[\\/]/.test(value)) return false;
  for (const seg of value.split(/[\\/]/)) {
    if (seg === '..') return false;
  }
  return true;
}

export const AttachmentBlockSchema = z.object({
  type: z.literal('attachment'),
  path: z
    .string()
    .min(1)
    .refine(
      isWorkspaceRelativePath,
      'path must be workspace-relative (no leading slash, no "..", no drive root, no NUL)',
    ),
  displayName: z.string().min(1),
  mediaType: z.string().min(1),
  sizeBytes: z.number().int().nonnegative(),
});
export type AttachmentBlock = z.infer<typeof AttachmentBlockSchema>;

export const ContentBlockSchema = z.discriminatedUnion('type', [
  TextBlockSchema,
  ThinkingBlockSchema,
  RedactedThinkingBlockSchema,
  ToolUseBlockSchema,
  ToolResultBlockSchema,
  ImageBlockSchema,
  AttachmentRefBlockSchema,
  AttachmentBlockSchema,
]);
export type ContentBlock = z.infer<typeof ContentBlockSchema>;

