1	import { describe, it, expect, beforeAll, afterAll, afterEach, vi } from 'vitest';
2	import {
3	  PostgreSqlContainer,
4	  type StartedPostgreSqlContainer,
5	} from '@testcontainers/postgresql';
6	import { PluginError } from '@ax/core';
7	import { createTestHarness, type TestHarness } from '@ax/test-harness';
8	import { createDatabasePostgresPlugin } from '@ax/database-postgres';
9	import { createConversationsPlugin } from '../plugin.js';
10	import type {
11	  CreateInput,
12	  CreateOutput,
13	  GetInput,
14	  GetOutput,
15	} from '../types.js';
16	
17	// ---------------------------------------------------------------------------
18	// Phase D Task 4: getConversation reads transcripts from the workspace's
19	// runner-native jsonl via `workspace:list` + `workspace:read`, NOT from the
20	// `conversation_turns` rows in postgres. The wire shape on the
21	// `conversations:get` hook is unchanged: subscribers (channel-web) still
22	// see `{ conversation, turns: Turn[] }`.
23	//
24	// Strategy: we mock `workspace:list` and `workspace:read` via vi.fn()
25	// service handlers in the test harness. Each test programs the mock for
26	// its scenario and asserts both the bus interactions AND the hook output.
27	// ---------------------------------------------------------------------------
28	
29	let container: StartedPostgreSqlContainer;
30	let connectionString: string;
31	const harnesses: TestHarness[] = [];
32	
33	interface ResolvePolicy {
34	  decide(call: { agentId: string; userId: string }):
35	    | 'allow'
36	    | 'forbid'
37	    | 'notfound';
38	}
39	
40	interface WorkspaceMocks {
41	  list: ReturnType<typeof vi.fn>;
42	  read: ReturnType<typeof vi.fn>;
43	}
44	
45	async function makeHarness(opts: {
46	  policy?: ResolvePolicy;
47	  workspaceList?: (input: { pathGlob?: string }) => Promise<{ paths: string[] }>;
48	  workspaceRead?: (input: {
49	    path: string;
50	  }) => Promise<{ found: true; bytes: Uint8Array } | { found: false }>;
51	}): Promise<{ h: TestHarness; mocks: WorkspaceMocks }> {
52	  const policy = opts.policy ?? { decide: () => 'allow' as const };
53	  // Default: workspace contains nothing ŌåÆ no jsonl found.
54	  const list = vi.fn(
55	    opts.workspaceList ??
56	      (async () => ({ paths: [] }) as { paths: string[] }),
57	  );
58	  const read = vi.fn(
59	    opts.workspaceRead ??
60	      (async () =>
61	        ({ found: false }) as { found: true; bytes: Uint8Array } | { found: false }),
62	  );
63	  const h = await createTestHarness({
64	    services: {
65	      'agents:resolve': async (
66	        _ctx,
67	        input: unknown,
68	      ): Promise<{ agent: { id: string; visibility: string } }> => {
69	        const call = input as { agentId: string; userId: string };
70	        const decision = policy.decide(call);
71	        if (decision === 'allow') {
72	          return { agent: { id: call.agentId, visibility: 'personal' } };
73	        }
74	        if (decision === 'notfound') {
75	          throw new PluginError({
76	            code: 'not-found',
77	            plugin: 'mock-agents',
78	            hookName: 'agents:resolve',
79	            message: `agent '${call.agentId}' not found`,
80	          });
81	        }
82	        throw new PluginError({
83	          code: 'forbidden',
84	          plugin: 'mock-agents',
85	          hookName: 'agents:resolve',
86	          message: `agent '${call.agentId}' forbidden for '${call.userId}'`,
87	        });
88	      },
89	      'workspace:list': async (_ctx, input: unknown) =>
90	        list(input as { pathGlob?: string }),
91	      'workspace:read': async (_ctx, input: unknown) =>
92	        read(input as { path: string }),
93	      // Phase B: workspace:apply is in the manifest calls; stub for bootstrap
94	      // (get-from-workspace tests don't exercise drop-turn).
95	      'workspace:apply': async () => ({ version: 'v-stub', delta: { before: null, after: 'v-stub', changes: [] } }),
96	    },
97	    plugins: [
98	      createDatabasePostgresPlugin({ connectionString }),
99	      createConversationsPlugin(),
100	    ],
101	  });
102	  harnesses.push(h);
103	  return { h, mocks: { list, read } };
104	}
105	
106	/**
107	 * Bind a `runner_session_id` directly via raw SQL ŌĆö Phase B's
108	 * `conversations:store-runner-session` hook ships in the same plugin but
109	 * we bypass it to keep these tests focused on getConversation.
110	 */
111	async function setRunnerSessionViaStore(
112	  conversationId: string,
